import{_ as a,o as t,c as n,a4 as o}from"./chunks/framework.Bv6IB9yN.js";const f=JSON.parse('{"title":"Accountability","description":"This page gives an overview of the accountabilities for HUNT Cloud.","frontmatter":{"title":"Accountability","category":"Govern science","permalink":"/govern-science/compliance/accountability/","description":"This page gives an overview of the accountabilities for HUNT Cloud."},"headers":[],"relativePath":"govern-science/compliance/accountability.md","filePath":"govern-science/compliance/accountability.md"}'),i={name:"govern-science/compliance/accountability.md"};function r(c,e,l,s,u,d){return t(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="accountability" tabindex="-1">Accountability <a class="header-anchor" href="#accountability" aria-label="Permalink to &quot;Accountability&quot;">​</a></h1><p><strong>Accountability for HUNT Cloud&#39;s compliance activities are as follows:</strong></p><p>HUNT Cloud is owned by the <a href="https://www.ntnu.edu" target="_blank" rel="noreferrer">Norwegian University of Science and Technology (NTNU)</a>, Trondheim, Norway. Enterprise number 974 767 880.</p><p>The Dean of the Faculty of Medicine and Health Sciences, <a href="https://www.ntnu.edu/mh/about/management-group" target="_blank" rel="noreferrer">Siri Forsmo</a> is responsible for our overall activities.</p><p>HUNT Cloud is organized under the Research section at the Faculty of Medicine and Health Sciences that is led by <a href="https://www.ntnu.edu/employees/solrun.j.valen" target="_blank" rel="noreferrer">Solrun Johanne Valen</a>.</p><p>The Head of HUNT Cloud, <a href="https://www.ntnu.edu/employees/oddgeir.lingaas.holmen" target="_blank" rel="noreferrer">Oddgeir Lingaas Holmen</a>, is responsible for HUNT Cloud&#39;s day-to-day operations, including management of information security and privacy, and the overall scientific development of products and services.</p><p>The Chief Technology Officer at HUNT Cloud, <a href="https://www.ntnu.no/ansatte/matus.kosut" target="_blank" rel="noreferrer">Matus Kosut</a>, is responsible for the technical development and operations at HUNT Cloud.</p><p>The Chief Compliance Officer at HUNT Cloud, <a href="https://www.ntnu.edu/employees/qussay.ghazeia" target="_blank" rel="noreferrer">Qussay Ghazeia</a>, is responsible for the implementation our internal and external audit programs.</p><p>Our official affiliation is HUNT Cloud, Faculty of Medicine and Health Sciences, Norwegian University of Science and Technology (NTNU), Trondheim, Norway.</p>',9)])])}const h=a(i,[["render",r]]);export{f as __pageData,h as default};
